const net = require('net')

const server = net.createServer((socket) => {
  socket.on('data', (data) => {
    console.log(data.toString('utf-8'));
    
  })

  const resp = Buffer.from('', 'hex')

  socket.write(resp)
})

server.listen(8080, "127.0.0.1", () => {
  console.log('Opened Server on', server.address());
})
